// Process page 1: build SQL + check if more pages needed
const resp = $input.first().json;
const ads = resp.data || [];
const meta = resp.meta || {};
const lastPage = meta.last_page || 1;

const result = buildSqlFromAds(ads);

// Output: SQL for this page + pagination info
const output = [{ json: { 
  sql: result.sql, 
  stats: result.stats,
  has_more: lastPage > 1,
  last_page: lastPage
}}];

// If more pages, also output page numbers
if (lastPage > 1) {
  for (let p = 2; p <= Math.min(lastPage, 20); p++) {
    output.push({ json: { page: p } });
  }
}

return output;

function buildSqlFromAds(ads) {
  if (ads.length === 0) {
    return { sql: "SELECT 'no_ads' as result", stats: { ads: 0, campaigns: 0, groups: 0 } };
  }

  const esc = (s) => (s || '').replace(/'/g, "''");
  const fixUrl = (u) => u ? (u.startsWith('//') ? 'https:' + u : u) : null;
  const GEOZO_STATUS = {
    1: 'processed', 2: 'moderation', 3: 'banned',
    4: 'stopped', 5: 'started', 41: 'budget_ended', 42: 'suspended'
  };

  // Extract unique campaigns and groups
  const campaignsMap = {};
  const groupsMap = {};
  for (const ad of ads) {
    if (ad.campaign_id && !campaignsMap[ad.campaign_id]) {
      campaignsMap[ad.campaign_id] = {
        campaign_id: ad.campaign_id,
        name: ad.campaign_name || null,
        campaign_type_id: ad.campaign_type_id || null
      };
    }
    if (ad.ad_group_id && !groupsMap[ad.ad_group_id]) {
      groupsMap[ad.ad_group_id] = {
        ad_group_id: ad.ad_group_id,
        campaign_id: ad.campaign_id,
        name: ad.group_ad_name || null
      };
    }
  }

  const campaigns = Object.values(campaignsMap);
  const groups = Object.values(groupsMap);

  const campaignSqls = campaigns.filter(c => c.name).map(c => {
    return `INSERT INTO campaigns (campaign_id, name, campaign_type_id, synced_at)
      VALUES (${c.campaign_id}, '${esc(c.name)}', ${c.campaign_type_id || 'NULL'}, NOW())
      ON CONFLICT (campaign_id) DO UPDATE SET
        name = EXCLUDED.name,
        campaign_type_id = COALESCE(EXCLUDED.campaign_type_id, campaigns.campaign_type_id),
        synced_at = NOW()`;
  });

  const groupSqls = groups.filter(g => g.name).map(g => {
    return `INSERT INTO ad_groups (ad_group_id, campaign_id, name, synced_at)
      VALUES (${g.ad_group_id}, ${g.campaign_id}, '${esc(g.name)}', NOW())
      ON CONFLICT (ad_group_id) DO UPDATE SET
        campaign_id = EXCLUDED.campaign_id,
        name = EXCLUDED.name,
        synced_at = NOW()`;
  });

  const adSqls = ads.filter(a => a.id).map(a => {
    const title = esc(a.title);
    const url = esc(a.url || '');
    const shortDesc = a.short_description ? "'" + esc(a.short_description) + "'" : 'NULL';
    const statusId = a.status_id || null;
    const status = GEOZO_STATUS[statusId] || 'unknown';
    const banReason = a.ban ? "'" + esc(typeof a.ban === 'string' ? a.ban : JSON.stringify(a.ban)) + "'" : 'NULL';
    const adRating = a.ad_rating?.name ? "'" + esc(a.ad_rating.name) + "'" : 'NULL';
    const geozoCreatedAt = a.created_at ? "'" + a.created_at + "'" : 'NULL';

    // Extract bid + country_code + geo_id from nested bids
    let bid = 'NULL';
    let countryCode = 'NULL';
    let geoId = 'NULL';
    if (a.bids && Array.isArray(a.bids)) {
      const findGeo = (obj) => {
        if (obj.type === 'countries' && obj.bid != null) {
          return { bid: parseFloat(obj.bid), cc: obj.id, gid: obj.geo_id };
        }
        if (obj.children) {
          for (const child of Object.values(obj.children)) {
            const r = findGeo(child);
            if (r) return r;
          }
        }
        return null;
      };
      for (const b of a.bids) {
        const r = findGeo(b);
        if (r) {
          bid = r.bid;
          countryCode = "'" + r.cc + "'";
          geoId = r.gid || 'NULL';
          break;
        }
      }
    }

    // Image URLs with protocol fix
    const imgSq = fixUrl(a.media_contents?.['1:1']?.url || a.media_contents?.original_square?.url);
    const imgHz = fixUrl(a.media_contents?.['16:9']?.url || a.media_contents?.original_horizontal_16x9?.url);
    const imgSquare = imgSq ? "'" + esc(imgSq) + "'" : 'NULL';
    const imgHoriz = imgHz ? "'" + esc(imgHz) + "'" : 'NULL';

    // Lifetime statistics from API
    const st = a.statistic || {};

    return `INSERT INTO teasers (ad_id, ad_group_id, campaign_id, title, original_url, short_description, geozo_status_id, status, bid, country_code, geo_id, image_square_path, image_horizontal_path, ban_reason, ad_rating, geozo_created_at, total_shows, total_clicks, total_money, total_cpc, total_ctr, total_roi, total_leads, total_leads_confirmed_money, total_cr, total_spend_lifetime, updated_at)
      VALUES (
        ${a.id}, ${a.ad_group_id || 'NULL'}, ${a.campaign_id || 'NULL'},
        '${title}', '${url}', ${shortDesc},
        ${statusId || 'NULL'}, '${status}', ${bid},
        ${countryCode}, ${geoId},
        ${imgSquare}, ${imgHoriz},
        ${banReason}, ${adRating}, ${geozoCreatedAt},
        ${st.shows_count||0}, ${st.clicks_count||0}, ${st.money||0},
        ${st.cpc||0}, ${st.confirmed_ctr||0}, ${st.roi_percentage||0},
        ${st.postbacks_total_count||0}, ${st.postbacks_confirmed_money||0}, ${st.cr||0},
        ${st.money||0}, NOW()
      )
      ON CONFLICT (ad_id) WHERE ad_id IS NOT NULL DO UPDATE SET
        ad_group_id = EXCLUDED.ad_group_id,
        campaign_id = EXCLUDED.campaign_id,
        title = EXCLUDED.title,
        original_url = EXCLUDED.original_url,
        short_description = EXCLUDED.short_description,
        geozo_status_id = EXCLUDED.geozo_status_id,
        status = EXCLUDED.status,
        bid = COALESCE(EXCLUDED.bid, teasers.bid),
        country_code = COALESCE(EXCLUDED.country_code, teasers.country_code),
        geo_id = COALESCE(EXCLUDED.geo_id, teasers.geo_id),
        image_square_path = COALESCE(EXCLUDED.image_square_path, teasers.image_square_path),
        image_horizontal_path = COALESCE(EXCLUDED.image_horizontal_path, teasers.image_horizontal_path),
        ban_reason = EXCLUDED.ban_reason,
        ad_rating = COALESCE(EXCLUDED.ad_rating, teasers.ad_rating),
        geozo_created_at = COALESCE(EXCLUDED.geozo_created_at, teasers.geozo_created_at),
        total_shows = EXCLUDED.total_shows,
        total_clicks = EXCLUDED.total_clicks,
        total_money = EXCLUDED.total_money,
        total_cpc = EXCLUDED.total_cpc,
        total_ctr = EXCLUDED.total_ctr,
        total_roi = EXCLUDED.total_roi,
        total_leads = EXCLUDED.total_leads,
        total_leads_confirmed_money = EXCLUDED.total_leads_confirmed_money,
        total_cr = EXCLUDED.total_cr,
        total_spend_lifetime = EXCLUDED.total_spend_lifetime,
        updated_at = NOW()`;
  });

  const allSql = [...campaignSqls, ...groupSqls, ...adSqls];
  allSql.push(`UPDATE ad_groups ag SET
    ad_count = (SELECT COUNT(*) FROM teasers t WHERE t.ad_group_id = ag.ad_group_id),
    ad_started_count = (SELECT COUNT(*) FROM teasers t WHERE t.ad_group_id = ag.ad_group_id AND t.geozo_status_id = 5)`);

  const sql = allSql.join(';\n') + ";\nSELECT 'ok' as result, " + ads.length + " as ads_synced, " + campaigns.length + " as campaigns_synced, " + groups.length + " as groups_synced";
  return { sql, stats: { ads: ads.length, campaigns: campaigns.length, groups: groups.length } };
}

// Re-use same SQL builder for subsequent pages
const resp = $input.first().json;
const ads = resp.data || [];

if (ads.length === 0) {
  return [{ json: { sql: "SELECT 'skip' as result", stats: { ads: 0 } } }];
}

const esc = (s) => (s || '').replace(/'/g, "''");
const fixUrl = (u) => u ? (u.startsWith('//') ? 'https:' + u : u) : null;
const GEOZO_STATUS = {
  1: 'processed', 2: 'moderation', 3: 'banned',
  4: 'stopped', 5: 'started', 41: 'budget_ended', 42: 'suspended'
};

const campaignsMap = {};
const groupsMap = {};
for (const ad of ads) {
  if (ad.campaign_id && !campaignsMap[ad.campaign_id]) {
    campaignsMap[ad.campaign_id] = { campaign_id: ad.campaign_id, name: ad.campaign_name };
  }
  if (ad.ad_group_id && !groupsMap[ad.ad_group_id]) {
    groupsMap[ad.ad_group_id] = { ad_group_id: ad.ad_group_id, campaign_id: ad.campaign_id, name: ad.group_ad_name };
  }
}

const sqls = [];
for (const c of Object.values(campaignsMap)) {
  if (c.name) sqls.push(`INSERT INTO campaigns (campaign_id, name, synced_at) VALUES (${c.campaign_id}, '${esc(c.name)}', NOW()) ON CONFLICT (campaign_id) DO UPDATE SET name = EXCLUDED.name, synced_at = NOW()`);
}
for (const g of Object.values(groupsMap)) {
  if (g.name) sqls.push(`INSERT INTO ad_groups (ad_group_id, campaign_id, name, synced_at) VALUES (${g.ad_group_id}, ${g.campaign_id}, '${esc(g.name)}', NOW()) ON CONFLICT (ad_group_id) DO UPDATE SET campaign_id = EXCLUDED.campaign_id, name = EXCLUDED.name, synced_at = NOW()`);
}

for (const a of ads.filter(a => a.id)) {
  const st = a.statistic || {};
  let bid = 'NULL', cc = 'NULL', gid = 'NULL';
  if (a.bids && Array.isArray(a.bids)) {
    const findGeo = (obj) => {
      if (obj.type === 'countries' && obj.bid != null) return { bid: parseFloat(obj.bid), cc: obj.id, gid: obj.geo_id };
      if (obj.children) { for (const child of Object.values(obj.children)) { const r = findGeo(child); if (r) return r; } }
      return null;
    };
    for (const b of a.bids) { const r = findGeo(b); if (r) { bid = r.bid; cc = "'" + r.cc + "'"; gid = r.gid || 'NULL'; break; } }
  }
  const imgSq = fixUrl(a.media_contents?.['1:1']?.url || a.media_contents?.original_square?.url);
  const imgHz = fixUrl(a.media_contents?.['16:9']?.url || a.media_contents?.original_horizontal_16x9?.url);

  sqls.push(`INSERT INTO teasers (ad_id, ad_group_id, campaign_id, title, original_url, short_description, geozo_status_id, status, bid, country_code, geo_id, image_square_path, image_horizontal_path, ban_reason, ad_rating, geozo_created_at, total_shows, total_clicks, total_money, total_cpc, total_ctr, total_roi, total_leads, total_leads_confirmed_money, total_cr, total_spend_lifetime, updated_at)
    VALUES (${a.id}, ${a.ad_group_id||'NULL'}, ${a.campaign_id||'NULL'}, '${esc(a.title)}', '${esc(a.url||'')}', ${a.short_description ? "'"+esc(a.short_description)+"'" : 'NULL'}, ${a.status_id||'NULL'}, '${GEOZO_STATUS[a.status_id]||'unknown'}', ${bid}, ${cc}, ${gid}, ${imgSq ? "'"+esc(imgSq)+"'" : 'NULL'}, ${imgHz ? "'"+esc(imgHz)+"'" : 'NULL'}, ${a.ban ? "'"+esc(JSON.stringify(a.ban))+"'" : 'NULL'}, ${a.ad_rating?.name ? "'"+a.ad_rating.name+"'" : 'NULL'}, ${a.created_at ? "'"+a.created_at+"'" : 'NULL'}, ${st.shows_count||0}, ${st.clicks_count||0}, ${st.money||0}, ${st.cpc||0}, ${st.confirmed_ctr||0}, ${st.roi_percentage||0}, ${st.postbacks_total_count||0}, ${st.postbacks_confirmed_money||0}, ${st.cr||0}, ${st.money||0}, NOW())
    ON CONFLICT (ad_id) WHERE ad_id IS NOT NULL DO UPDATE SET ad_group_id=EXCLUDED.ad_group_id, campaign_id=EXCLUDED.campaign_id, title=EXCLUDED.title, original_url=EXCLUDED.original_url, short_description=EXCLUDED.short_description, geozo_status_id=EXCLUDED.geozo_status_id, status=EXCLUDED.status, bid=COALESCE(EXCLUDED.bid,teasers.bid), country_code=COALESCE(EXCLUDED.country_code,teasers.country_code), geo_id=COALESCE(EXCLUDED.geo_id,teasers.geo_id), image_square_path=COALESCE(EXCLUDED.image_square_path,teasers.image_square_path), image_horizontal_path=COALESCE(EXCLUDED.image_horizontal_path,teasers.image_horizontal_path), ban_reason=EXCLUDED.ban_reason, ad_rating=COALESCE(EXCLUDED.ad_rating,teasers.ad_rating), geozo_created_at=COALESCE(EXCLUDED.geozo_created_at,teasers.geozo_created_at), total_shows=EXCLUDED.total_shows, total_clicks=EXCLUDED.total_clicks, total_money=EXCLUDED.total_money, total_cpc=EXCLUDED.total_cpc, total_ctr=EXCLUDED.total_ctr, total_roi=EXCLUDED.total_roi, total_leads=EXCLUDED.total_leads, total_leads_confirmed_money=EXCLUDED.total_leads_confirmed_money, total_cr=EXCLUDED.total_cr, total_spend_lifetime=EXCLUDED.total_spend_lifetime, updated_at=NOW()`);
}

sqls.push(`UPDATE ad_groups ag SET ad_count = (SELECT COUNT(*) FROM teasers t WHERE t.ad_group_id = ag.ad_group_id), ad_started_count = (SELECT COUNT(*) FROM teasers t WHERE t.ad_group_id = ag.ad_group_id AND t.geozo_status_id = 5)`);

const sql = sqls.join(';\n') + ";\nSELECT 'ok' as result, " + ads.length + " as ads_synced";
return [{ json: { sql } }];
